mapper.select:
SELECT c.id, c.name, c.room, c.begin_date, c.end_date,
       c.master_id, c.subject, c.create_time, c.update_time,
       e.name AS master_name
FROM clazz c
LEFT JOIN emp e ON c.master_id = e.id


        AND c.name LIKE CONCAT('%', #{name}, '%')


        AND c.subject = #{subject}


        AND c.begin_date >= #{begin}


        AND c.end_date <= #{end}


ORDER BY c.update_time DESC

mapper.update:
UPDATE clazz
name = #{name}, room = #{room}, begin_date = #{beginDate}, end_date = #{endDate}, master_id = #{masterId}, subject = #{subject},
WHERE id = #{id}
